-- Kap 4 (läsnings- och tolkningsproblem) → scholarly_notes på de fyra namngivna
-- inskrifterna. Källström 2007. Applicerad via MCP.
update public.runic_inscriptions set scholarly_notes = 'Läsningsproblem (Källström 2007, kap 4.4.1): inskriften rymmer två ristarformler — Gunnarr fáði rúnaR þessaR i inledningen och Vífinn þetta fáði i den lodräta slutraden. Vi-Finn kan vara viets föreståndare som bestyrker Gunnars förlikning, eller Gunnars arvtagare. Oklundaristningen är känd som ett tidigt rättsligt dokument om fredlöshet/asyl.' where id='20e8241f-0b79-42c3-93be-2c6b9decb105';
update public.runic_inscriptions set scholarly_notes = 'Läsningsproblem (Källström 2007, kap 4.4.2): den ovanliga formuleringen Tirvi runaR har uppfattats som en ristarsignatur (Tyrve/Tjarve), men någon sådan ristare är annars okänd. Per Stille tillskriver i stället ristningen ristaren Sven (jfr U 284). Brödernas namn saknas. Frågan lämnas öppen.' where id='0ef9ce04-0e12-4f14-b650-bc345baff451';
update public.runic_inscriptions set scholarly_notes = 'Läsningsproblem (Källström 2007, kap 4.4.3): en bokstavlig läsning av B-sidan antyder att Vigmund och en kvinna, Åfrid (troligen hans hustru), själva högg minnesmärket — Jansson såg här möjligen en kvinnlig runmästare. v. Friesen menade att formen kvikvan snarare avslöjar Vigmund själv som mästaren, medan Åfrid inte har huggit. Wessén: osignerad, ristaren stod Fot nära.' where id='16be39e0-799d-40fe-a4b1-7ac9ce39c382';
update public.runic_inscriptions set scholarly_notes = 'Läsningsproblem (Källström 2007, kap 4.4.4): partiet Hiogg Assur (Assur högg) har alltid uppfattats som en ristarformel, men det står insprängt mellan två ännu osäkert tolkade partier, vilket reser frågan om det verkligen kan brytas ut som en självständig ristarsignatur.' where id='ef250dea-acac-425b-ad9c-c552d796bd49';
